#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

function normText(value = "") {
  return String(value || "").trim();
}

function normArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(values = []) {
  return [...new Set(normArray(values).map((row) => normText(row)).filter(Boolean))];
}

function indexRepresentativenessProfiles(effect = {}) {
  const profiles = new Map();
  for (const row of normArray(effect?.screeningLearning?.configurationRepresentativeness?.profiles)) {
    const geometryProfile = normText(row?.geometryProfile);
    if (!geometryProfile) continue;
    profiles.set(geometryProfile, {
      modelType: normText(row?.modelType),
      analyzerFamily: normText(row?.analyzerFamily),
      structuralSignature: normText(row?.structuralSignature)
    });
  }
  return profiles;
}

function buildEffectPriorBundle(effect = {}) {
  const profilesByGeometry = indexRepresentativenessProfiles(effect);
  const priors = normArray(effect?.parameterLearning?.derivedPriors?.priors)
    .map((row) => {
      const geometryProfile = normText(row?.geometryProfile);
      const representativeness = profilesByGeometry.get(geometryProfile) || {};
      const anchorProfiles = normArray(row?.anchorProfiles)
        .map((anchor) => ({
          parameterValue: anchor?.parameterValue,
          sampleCount: Number(anchor?.sampleCount || 0),
          meanTemporalMotion: Number(anchor?.meanTemporalMotion || 0),
          meanTemporalColorDelta: Number(anchor?.meanTemporalColorDelta || 0),
          meanTemporalBrightnessDelta: Number(anchor?.meanTemporalBrightnessDelta || 0),
          meanNonBlankRatio: Number(anchor?.meanNonBlankRatio || 0),
          temporalSignatureHints: unique(anchor?.temporalSignatureHints),
          behaviorHints: unique(anchor?.behaviorHints)
        }))
        .filter((anchor) => anchor.sampleCount > 0);
      if (!geometryProfile || !anchorProfiles.length) return null;
      return {
        parameterName: normText(row?.parameterName),
        geometryProfile,
        modelType: normText(representativeness?.modelType),
        analyzerFamily: normText(representativeness?.analyzerFamily),
        paletteMode: normText(row?.paletteMode),
        confidence: normText(row?.confidence),
        configurationCoverageStatus: normText(row?.configurationCoverageStatus),
        configurationProfileCount: Number(row?.configurationProfileCount || 0),
        distinctAnchorCount: Number(row?.distinctAnchorCount || 0),
        sampleCount: Number(row?.sampleCount || 0),
        structuralSignatures: unique(row?.structuralSignatures),
        anchorProfiles
      };
    })
    .filter(Boolean);
  return {
    effectName: normText(effect?.effectName),
    priorCount: priors.length,
    priors
  };
}

function buildBundle(trainingSet = {}) {
  const effects = {};
  const selectorReadyEffects = [];
  for (const effect of normArray(trainingSet?.effects)) {
    const effectName = normText(effect?.effectName);
    if (!effectName) continue;
    const priorBundle = buildEffectPriorBundle(effect);
    if (!priorBundle.priorCount) continue;
    effects[effectName] = priorBundle;
    selectorReadyEffects.push(effectName);
  }
  return {
    artifactType: "sequencer_derived_parameter_priors_bundle",
    artifactVersion: "1.0",
    generatedAt: new Date().toISOString(),
    sourceArtifactType: normText(trainingSet?.artifactType),
    sourceArtifactVersion: normText(trainingSet?.artifactVersion),
    effectCount: Object.keys(effects).length,
    selectorReadyEffects: selectorReadyEffects.sort(),
    effectsByName: Object.fromEntries(Object.entries(effects).sort(([a], [b]) => a.localeCompare(b)))
  };
}

function writeJsModule(bundle, outputPath) {
  const text = JSON.stringify(bundle, null, 2);
  fs.writeFileSync(
    outputPath,
    "// Auto-generated by scripts/sequencer-render-training/tooling/export-derived-parameter-priors-bundle.mjs\n"
      + "export const DERIVED_PARAMETER_PRIORS_BUNDLE = "
      + text
      + ";\n"
  );
}

function main() {
  const args = process.argv.slice(2);
  const inputIndex = args.indexOf("--input");
  const outputIndex = args.indexOf("--output");
  if (inputIndex < 0 || outputIndex < 0 || !args[inputIndex + 1] || !args[outputIndex + 1]) {
    throw new Error("Usage: node export-derived-parameter-priors-bundle.mjs --input <training-set.json> --output <bundle.js>");
  }
  const inputPath = path.resolve(args[inputIndex + 1]);
  const outputPath = path.resolve(args[outputIndex + 1]);
  const trainingSet = JSON.parse(fs.readFileSync(inputPath, "utf8"));
  const bundle = buildBundle(trainingSet);
  writeJsModule(bundle, outputPath);
  process.stdout.write(`${JSON.stringify({ output: outputPath, effectCount: bundle.effectCount }, null, 2)}\n`);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  main();
}

export { buildBundle };
